//! # Sacramento Capitol — Topological Landmark
//!
//! Generates a synthetic 3D manifold of the California State Capitol.
//!
//! Projects the "Sacramento Handshake" as a Pleromatic Frame.

use distributed_inference::app_streaming::{AppState, HolographicAppBridge};
use distributed_inference::holographic_reconstruction::VoxelCoord;
use std::collections::HashMap;

fn main() -> Result<(), Box<dyn std::error::Error>> {
    println!(" [ GENERATING SACRAMENTO LANDMARK: STATE CAPITOL ] ");

    let mut sac_voxels = Vec::new();

    // 1. The Base (x=10..30, y=10..20, z=5..15)
    for x in 10..30 {
        for y in 10..20 {
            for z in 5..15 {
                if x == 10 || x == 29 || y == 10 || y == 19 || z == 5 || z == 14 {
                    sac_voxels.push(VoxelCoord { x, y, z });
                }
            }
        }
    }

    // 2. The Dome (Cylinder at center)
    let center_x = 20.0;
    let center_y = 15.0;
    let radius = 5.0;
    for z in 15..30 {
        for x in 10..30 {
            for y in 10..20 {
                let dx = x as f32 - center_x;
                let dy = y as f32 - center_y;
                let dist = (dx * dx + dy * dy).sqrt();
                if (dist - radius).abs() < 1.0 {
                    sac_voxels.push(VoxelCoord { x, y, z });
                }
            }
        }
    }

    println!(" Generated Capitol: {} voxels", sac_voxels.len());

    let state = AppState {
        app_id: "sac-capitol".into(),
        components: HashMap::from([
            ("location".into(), "Sacramento".into()),
            ("landmark".into(), "State Capitol".into()),
        ]),
        active_coords: sac_voxels,
    };

    let mut bridge = HolographicAppBridge::new("sac-node-1");
    let frame = bridge.capture_frame(&state, vec![]);

    println!(" [ EMITTING SAC HANDSHAKE ] ");
    let path = "sac_handshake.frame";
    std::fs::write(path, bincode::serialize(&frame)?)?;
    println!(" Saved Handshake to: {}", path);

    Ok(())
}
